render.css:
.tesseract-container { display: flex; align-items: center; justify-content: center; height: 180px; perspective: 800px; }
.tesseract-scene { position: relative; width: 120px; height: 120px; transform-style: preserve-3d; }
.tesseract-cube { position: absolute; top: 50%; left: 50%; transform-style: preserve-3d; }
.tesseract-cube.outer { width: 80px; height: 80px; margin: -40px 0 0 -40px; animation: tesseractRotateOuter 12s linear infinite; }
.tesseract-cube.inner { width: 40px; height: 40px; margin: -20px 0 0 -20px; animation: tesseractRotateInner 8s linear infinite reverse; }
.tesseract-face { position: absolute; width: 100%; height: 100%; border: 1px solid var(--ct-text-muted); background: transparent; }
.tesseract-cube.outer .tesseract-face { border-color: var(--ct-text-strong); }
.tesseract-cube.outer .front  { transform: translateZ(40px); }
.tesseract-cube.outer .back   { transform: translateZ(-40px) rotateY(180deg); }
.tesseract-cube.outer .right  { transform: rotateY(90deg) translateZ(40px); }
.tesseract-cube.outer .left   { transform: rotateY(-90deg) translateZ(40px); }
.tesseract-cube.outer .top    { transform: rotateX(90deg) translateZ(40px); }
.tesseract-cube.outer .bottom { transform: rotateX(-90deg) translateZ(40px); }
.tesseract-cube.inner .front  { transform: translateZ(20px); }
.tesseract-cube.inner .back   { transform: translateZ(-20px) rotateY(180deg); }
.tesseract-cube.inner .right  { transform: rotateY(90deg) translateZ(20px); }
.tesseract-cube.inner .left   { transform: rotateY(-90deg) translateZ(20px); }
.tesseract-cube.inner .top    { transform: rotateX(90deg) translateZ(20px); }
.tesseract-cube.inner .bottom { transform: rotateX(-90deg) translateZ(20px); }
@keyframes tesseractRotateOuter { from { transform: rotateX(0) rotateY(0) rotateZ(0); } to { transform: rotateX(360deg) rotateY(360deg) rotateZ(360deg); } }
@keyframes tesseractRotateInner { from { transform: rotateX(0) rotateY(0); } to { transform: rotateX(-360deg) rotateY(-360deg); } }
